        tile[2] += sc * (Gx[6] * xij + Gx[8]) * (Gy[0]) * (Gz[1]);
        tile[3] += sc * (Gx[7]) * (Gy[0] * yij + Gy[2]) * (Gz[0]);
        tile[4] += sc * (Gx[6]) * (Gy[1] * yij + Gy[3]) * (Gz[0]);
        tile[5] += sc * (Gx[6]) * (Gy[0] * yij + Gy[2]) * (Gz[1]);
        tile[6] += sc * (Gx[7]) * (Gy[0]) * (Gz[0] * zij + Gz[2]);
        tile[7] += sc * (Gx[6]) * (Gy[1]) * (Gz[0] * zij + Gz[2]);
        tile[8] += sc * (Gx[6]) * (Gy[0]) * (Gz[1] * zij + Gz[3]);
        tile[9] += sc * (Gx[5] * xij + Gx[7]) * (Gy[2]) * (Gz[0]);
        tile[10] += sc * (Gx[4] * xij + Gx[6]) * (Gy[3]) * (Gz[0]);
        tile[11] += sc * (Gx[4] * xij + Gx[6]) * (Gy[2]) * (Gz[1]);
        tile[12] += sc * (Gx[5]) * (Gy[2] * yij + Gy[4]) * (Gz[0]);
        tile[13] += sc * (Gx[4]) * (Gy[3] * yij + Gy[5]) * (Gz[0]);
        tile[14] += sc * (Gx[4]) * (Gy[2] * yij + Gy[4]) * (Gz[1]);
        tile[15] += sc * (Gx[5]) * (Gy[2]) * (Gz[0] * zij + Gz[2]);
        tile[16] += sc * (Gx[4]) * (Gy[3]) * (Gz[0] * zij + Gz[2]);
        tile[17] += sc * (Gx[4]) * (Gy[2]) * (Gz[1] * zij + Gz[3]);
        tile[18] += sc * (Gx[5] * xij + Gx[7]) * (Gy[0]) * (Gz[2]);
        tile[19] += sc * (Gx[4] * xij + Gx[6]) * (Gy[1]) * (Gz[2]);
        tile[20] += sc * (Gx[4] * xij + Gx[6]) * (Gy[0]) * (Gz[3]);
        tile[21] += sc * (Gx[5]) * (Gy[0] * yij + Gy[2]) * (Gz[2]);
        tile[22] += sc * (Gx[4]) * (Gy[1] * yij + Gy[3]) * (Gz[2]);
        tile[23] += sc * (Gx[4]) * (Gy[0] * yij + Gy[2]) * (Gz[3]);
        tile[24] += sc * (Gx[5]) * (Gy[0]) * (Gz[2] * zij + Gz[4]);
        tile[25] += sc * (Gx[4]) * (Gy[1]) * (Gz[2] * zij + Gz[4]);
        tile[26] += sc * (Gx[4]) * (Gy[0]) * (Gz[3] * zij + Gz[5]);
        tile[27] += sc * (Gx[3] * xij + Gx[5]) * (Gy[4]) * (Gz[0]);
        tile[28] += sc * (Gx[2] * xij + Gx[4]) * (Gy[5]) * (Gz[0]);
        tile[29] += sc * (Gx[2] * xij + Gx[4]) * (Gy[4]) * (Gz[1]);
        tile[30] += sc * (Gx[3]) * (Gy[4] * yij + Gy[6]) * (Gz[0]);
        tile[31] += sc * (Gx[2]) * (Gy[5] * yij + Gy[7]) * (Gz[0]);
        tile[32] += sc * (Gx[2]) * (Gy[4] * yij + Gy[6]) * (Gz[1]);
        tile[33] += sc * (Gx[3]) * (Gy[4]) * (Gz[0] * zij + Gz[2]);
        tile[34] += sc * (Gx[2]) * (Gy[5]) * (Gz[0] * zij + Gz[2]);
        tile[35] += sc * (Gx[2]) * (Gy[4]) * (Gz[1] * zij + Gz[3]);
        tile[36] += sc * (Gx[3] * xij + Gx[5]) * (Gy[2]) * (Gz[2]);
