        tile[64] += sc * (Gx[0] * xij + Gx[2]) * (Gy[5]) * (Gz[2]);
        tile[65] += sc * (Gx[0] * xij + Gx[2]) * (Gy[4]) * (Gz[3]);
        tile[66] += sc * (Gx[1]) * (Gy[4] * yij + Gy[6]) * (Gz[2]);
        tile[67] += sc * (Gx[0]) * (Gy[5] * yij + Gy[7]) * (Gz[2]);
        tile[68] += sc * (Gx[0]) * (Gy[4] * yij + Gy[6]) * (Gz[3]);
        tile[69] += sc * (Gx[1]) * (Gy[4]) * (Gz[2] * zij + Gz[4]);
        tile[70] += sc * (Gx[0]) * (Gy[5]) * (Gz[2] * zij + Gz[4]);
        tile[71] += sc * (Gx[0]) * (Gy[4]) * (Gz[3] * zij + Gz[5]);
        tile[72] += sc * (Gx[1] * xij + Gx[3]) * (Gy[2]) * (Gz[4]);
        tile[73] += sc * (Gx[0] * xij + Gx[2]) * (Gy[3]) * (Gz[4]);
        tile[74] += sc * (Gx[0] * xij + Gx[2]) * (Gy[2]) * (Gz[5]);
        tile[75] += sc * (Gx[1]) * (Gy[2] * yij + Gy[4]) * (Gz[4]);
        tile[76] += sc * (Gx[0]) * (Gy[3] * yij + Gy[5]) * (Gz[4]);
        tile[77] += sc * (Gx[0]) * (Gy[2] * yij + Gy[4]) * (Gz[5]);
        tile[78] += sc * (Gx[1]) * (Gy[2]) * (Gz[4] * zij + Gz[6]);
        tile[79] += sc * (Gx[0]) * (Gy[3]) * (Gz[4] * zij + Gz[6]);
        tile[80] += sc * (Gx[0]) * (Gy[2]) * (Gz[5] * zij + Gz[7]);
        tile[81] += sc * (Gx[1] * xij + Gx[3]) * (Gy[0]) * (Gz[6]);
        tile[82] += sc * (Gx[0] * xij + Gx[2]) * (Gy[1]) * (Gz[6]);
        tile[83] += sc * (Gx[0] * xij + Gx[2]) * (Gy[0]) * (Gz[7]);
        tile[84] += sc * (Gx[1]) * (Gy[0] * yij + Gy[2]) * (Gz[6]);
        tile[85] += sc * (Gx[0]) * (Gy[1] * yij + Gy[3]) * (Gz[6]);
        tile[86] += sc * (Gx[0]) * (Gy[0] * yij + Gy[2]) * (Gz[7]);
        tile[87] += sc * (Gx[1]) * (Gy[0]) * (Gz[6] * zij + Gz[8]);
        tile[88] += sc * (Gx[0]) * (Gy[1]) * (Gz[6] * zij + Gz[8]);
        tile[89] += sc * (Gx[0]) * (Gy[0]) * (Gz[7] * zij + Gz[9]);
      }
    }
  }

  // Write output tile.
  double* out = eri_out + static_cast<int64_t>(t) * static_cast<int64_t>(90);
  out[0] = tile[0];
